type EbookMutation struct {
	config
	op                      Op
	typ                     string
	id                      *uuid.UUID
	created_at              *time.Time
	updated_at              *time.Time
	tenant_id               *uuid.UUID
	bib_record_id           *uuid.UUID
	file_url                *string
	format                  *ebook.Format
	drm_policy              *ebook.DrmPolicy
	lending_model           *ebook.LendingModel
	max_concurrent_loans    *int
	addmax_concurrent_loans *int
	loan_duration_days      *int
	addloan_duration_days   *int
	is_purchasable          *bool
	price                   *decimal.Decimal
	file_size               *int64
	addfile_size            *int64
	checksum                *string
	clearedFields           map[string]struct{}
	done                    bool
	oldValue                func(context.Context) (*Ebook, error)
	predicates              []predicate.Ebook
}

var _ ent.Mutation = (*EbookMutation)(nil)

// ebookOption allows management of the mutation configuration using functional options.
type ebookOption func(*EbookMutation)

// newEbookMutation creates new mutation for the Ebook entity.
func newEbookMutation(c config, op Op, opts ...ebookOption) *EbookMutation {
	m := &EbookMutation{
		config:        c,
		op:            op,
		typ:           TypeEbook,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withEbookID sets the ID field of the mutation.
func withEbookID(id uuid.UUID) ebookOption {
	return func(m *EbookMutation) {
		var (
			err   error
			once  sync.Once
			value *Ebook
		)
		m.oldValue = func(ctx context.Context) (*Ebook, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().Ebook.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withEbook sets the old Ebook of the mutation.
func withEbook(node *Ebook) ebookOption {
	return func(m *EbookMutation) {
		m.oldValue = func(context.Context) (*Ebook, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

