// fineOption allows management of the mutation configuration using functional options.
type fineOption func(*FineMutation)

// newFineMutation creates new mutation for the Fine entity.
func newFineMutation(c config, op Op, opts ...fineOption) *FineMutation {
	m := &FineMutation{
		config:        c,
		op:            op,
		typ:           TypeFine,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withFineID sets the ID field of the mutation.
func withFineID(id uuid.UUID) fineOption {
	return func(m *FineMutation) {
		var (
			err   error
			once  sync.Once
			value *Fine
		)
		m.oldValue = func(ctx context.Context) (*Fine, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().Fine.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withFine sets the old Fine of the mutation.
func withFine(node *Fine) fineOption {
	return func(m *FineMutation) {
		m.oldValue = func(context.Context) (*Fine, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

